import React from 'react';
import { Link, useParams } from 'react-router-dom';
import { Helmet } from 'react-helmet-async';

export default function AccountOrderDetailPage() {
  const { id } = useParams();

  return (
    <div>
      <Helmet>
        <title>Order {id ? `#${String(id).slice(-8)}` : ''} | Nova Shop</title>
      </Helmet>
      <p style={{ marginBottom: '1rem' }}>
        <Link to="/account/orders" style={{ fontSize: '0.9rem' }}>
          ← Back to orders
        </Link>
      </p>
      <h2 style={{ fontSize: '1.25rem', marginBottom: '0.75rem' }}>Order detail</h2>
      <p style={{ color: 'var(--gray)', marginBottom: '1rem' }}>
        Order ID: <code style={{ fontSize: '0.85rem' }}>{id}</code>
      </p>
      <p style={{ color: 'var(--gray)', maxWidth: 480 }}>
        Connect this view to <code>GET /api/orders/:id</code> to show line items, shipping, and status history.
      </p>
    </div>
  );
}
